    alignItems: "center",
    justifyContent: "center",
    color: "#555",
  },
  navRow: {
    position: "absolute",
    bottom: 10,
    left: "50%",
    transform: "translateX(-50%)",
    display: "flex",
    alignItems: "center",
    gap: 10,
    background: "rgba(0,0,0,0.7)",
    padding: "4px 14px",
    borderRadius: 20,
  },
  navBtn: {
    background: "none",
    border: "none",
    color: "#fff",
    fontSize: "1.3rem",
    cursor: "pointer",
  },
  name: { fontWeight: 800, fontSize: "1.8rem", color: "#f0f0ee" },
  price: { fontWeight: 800, fontSize: "1.5rem", color: "#e8ff3a" },
  specs: { display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 },
  spec: {
    background: "#1e2022",
    padding: "10px 14px",
    borderRadius: 10,
    display: "flex",
    flexDirection: "column",
    gap: 2,
  },
  specLabel: { fontSize: 11, color: "#555", textTransform: "uppercase" },
  specVal: { fontSize: 14, color: "#f0f0ee" },
  sectionLabel: {
    fontSize: 11,
    color: "#555",
    textTransform: "uppercase",
    letterSpacing: "0.08em",
    marginBottom: 8,
  },
  tag: {
    background: "#1e2022",
    border: "1px solid #2a2c2f",
    padding: "4px 12px",
    borderRadius: 20,
    fontSize: 12,
    color: "#888",
  },
  seller: {
    display: "flex",
    alignItems: "center",
    gap: 12,
    background: "#1e2022",
    padding: "12px 16px",
    borderRadius: 12,
  },
  avatar: {
    width: 40,
    height: 40,
    borderRadius: "50%",
