    borderRadius: 8,
    padding: "12px",
    cursor: "pointer",
  },
  btnGreen: {
    background: "rgba(58,255,176,0.15)",
    color: "#3affb0",
    border: "1px solid #3affb0",
    borderRadius: 8,
